    val n = s.length

    // Precompute prefix L counts
    val prefixL = Array.ofDim[Int](n + 1)
    for (i <- 1 to n) {
        prefixL(i) = prefixL(i - 1) + (if (s(i - 1) == 'L') 1 else 0)
    }

    // Precompute suffix CT counts
    val suffixCT = Array.ofDim[Int](n + 1)
    val suffixT = Array.ofDim[Int](n + 1)
    for (i <- n - 1 to 0 by -1) {
        suffixT(i) = suffixT(i + 1) + (if (s(i) == 'T') 1 else 0)
        suffixCT(i) = suffixCT(i + 1) + (if (s(i) == 'C') suffixT(i + 1) else 0)
    }

    // Original LCT count without insertion
    var original = 0L
    var cCount = 0L
    for (i <- n - 1 to 0 by -1) {
        if (s(i) == 'T') {
            // Do nothing
        } else if (s(i) == 'C') {
            cCount += suffixT(i + 1)
        } else if (s(i) == 'L') {
